diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..65812489ad9b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,69 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub(smin(X + C, Y), smin(X, Y)) --> select(X < Y, C, 0)
+  // sub(smin(X + C, Y), smin(X, Y)) --> select(X < Y, C, 0)
+  // sub(smax(X + C, Y), smax(X, Y)) --> select(X >= Y, C, 0)
+  // sub(umin(X + C, Y), umin(X, Y)) --> select(X < Y, C, 0)
+  // sub(umax(X + C, Y), umax(X, Y)) --> select(X >= Y, C, 0)
+  // where C is a constant.
+  // Also handles or disjoint(X, C) which is equivalent to X + C when the bits
+  // of C are known to be 0 in X.
+  Value *MinMax0Op0, *MinMax0Op1;
+  Value *MinMax1Op0, *MinMax1Op1;
+  const APInt *C;
+  if (auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0)) {
+    Intrinsic::ID ID = MinMax0->getIntrinsicID();
+    if (ID == MinMax->getIntrinsicID() && MinMax0->hasOneUse() &&
+        Op1->hasOneUse()) {
+      MinMax0Op0 = MinMax0->getLHS();
+      MinMax0Op1 = MinMax0->getRHS();
+      MinMax1Op0 = MinMax->getLHS();
+      MinMax1Op1 = MinMax->getRHS();
+      // Check if MinMax0Op0 is MinMax1Op0 + C
+      BinaryOperator *Add = nullptr;
+      bool IsAdd = match(MinMax0Op0, m_Add(m_Specific(MinMax1Op0), m_APInt(C))) &&
+                   match(MinMax0Op0, m_BinOp(Add));
+      // Also check for or disjoint(X, C) which is equivalent to X + C
+      bool IsOrDisjoint = false;
+      if (!IsAdd) {
+        if (match(MinMax0Op0, m_Or(m_Specific(MinMax1Op0), m_APInt(C)))) {
+          if (auto *PDI = dyn_cast<PossiblyDisjointInst>(MinMax0Op0)) {
+            if (PDI->isDisjoint()) {
+              IsOrDisjoint = true;
+            }
+          }
+        }
+      }
+      if (IsAdd || IsOrDisjoint) {
+        // Check that the other operands match (MinMax0Op1 == MinMax1Op1)
+        if (MinMax0Op1 == MinMax1Op1) {
+          bool IsSigned = (ID == Intrinsic::smin || ID == Intrinsic::smax);
+          // Check for necessary no-wrap flags (only for add, not or disjoint)
+          if (IsAdd) {
+            if ((IsSigned && !Add->hasNoSignedWrap()) ||
+                (!IsSigned && !Add->hasNoUnsignedWrap()))
+              return nullptr;
+          }
+          // smin/smax(X + C, Y) - smin/smax(X, Y) -> select(X < Y, C, 0) or select(X >= Y, C, 0)
+          bool IsMin = (ID == Intrinsic::smin || ID == Intrinsic::umin);
+          // For min: if X < Y, result is C, else 0
+          // For max: if X >= Y, result is C, else 0
+          CmpInst::Predicate Pred = IsMin ? (IsSigned ? CmpInst::ICMP_SLT : CmpInst::ICMP_ULT)
+                                          : (IsSigned ? CmpInst::ICMP_SGE : CmpInst::ICMP_UGE);
+          Value *Cmp = Builder.CreateICmp(Pred, MinMax1Op0, MinMax1Op1);
+          // If C == 1, use zext(i1) instead of select
+          if (C->isOne()) {
+            return new ZExtInst(Cmp, Ty);
+          }
+          Value *NewC = ConstantInt::get(Ty, *C);
+          Value *Zero = ConstantInt::get(Ty, 0);
+          return SelectInst::Create(Cmp, NewC, Zero);
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

